@namespace Lumeo

<DropdownMenu @bind-Open="_open">
    @* The menu ARIA (role=button + aria-haspopup/expanded/controls) lives on the
       DropdownMenuTrigger wrapper. Make THAT wrapper the focusable host (tabindex=0)
       and drop the inner native <button> out of the tab order (tabindex=-1), so the
       single tab stop is the element that actually carries the menu semantics —
       otherwise a screen reader landed on a bare, ARIA-less <button> (triage #113).
       The wrapper also gets the keyboard entry point the menu-button pattern needs:
       Enter/Space toggle and ArrowDown/ArrowUp open the menu (triage #114). A div
       with role=button does NOT fire click on Enter/Space natively, and Arrow keys
       never did, so without this handler the closed trigger was keyboard-dead once
       the inner button left the tab order. tabindex + the keydown EventCallback are
       splatted onto the wrapper via the trigger's AdditionalAttributes. *@
    <DropdownMenuTrigger Disabled="Disabled" @attributes="TriggerAttributes">
        <Button Variant="Variant" Size="Size" Disabled="Disabled" Class="@CssClass" tabindex="-1">
            @if (ChildContent != null)
            {
                @ChildContent
            }
            else
            {
                @Text
            }
            <SvgGlyph Svg="@(LumeoIcons.ChevronDown)" Class="h-4 w-4 shrink-0 opacity-70 transition-transform duration-200 group-data-[state=open]:rotate-180" />
        </Button>
    </DropdownMenuTrigger>
    <DropdownMenuContent>
        @MenuContent
    </DropdownMenuContent>
</DropdownMenu>

@code {
    /// <summary>Button label text. Ignored when <see cref="ChildContent"/> is supplied.</summary>
    [Parameter] public string? Text { get; set; }
    /// <summary>Custom button content (overrides <see cref="Text"/>). The trailing chevron icon is always appended.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }
    /// <summary>The dropdown menu's items, rendered inside a <c>DropdownMenuContent</c>.</summary>
    [Parameter] public RenderFragment? MenuContent { get; set; }
    /// <summary>Visual style forwarded to the underlying <c>Button</c> (default <see cref="Button.ButtonVariant.Default"/>).</summary>
    [Parameter] public Button.ButtonVariant Variant { get; set; } = Button.ButtonVariant.Default;
    /// <summary>Size forwarded to the underlying <c>Button</c> (default <see cref="Button.ButtonSize.Default"/>).</summary>
    [Parameter] public Button.ButtonSize Size { get; set; } = Button.ButtonSize.Default;
    /// <summary>Disables the trigger, removes it from the tab order, and force-closes the menu if it was open.</summary>
    [Parameter] public bool Disabled { get; set; }
    /// <summary>Additional CSS classes merged onto the underlying <c>Button</c>.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Unmatched attributes splatted onto the focusable trigger wrapper (author-supplied values win over the built-in <c>tabindex</c>/<c>onkeydown</c>).</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool _open;
    // Tracks the previously-applied Disabled value so an unrelated re-render
    // (same Disabled) never touches open state — only a real false->true edge
    // force-closes the menu.
    private bool _wasDisabled;

    private string CssClass => Cx.Merge("gap-1.5", Class);

    // Wrapper attributes: make the ARIA-bearing trigger the single tab stop and
    // wire its keyboard entry point, then fold in any consumer-supplied splat last
    // so the author can still override (e.g. a custom tabindex). The keydown value
    // is an EventCallback stored under the `onkeydown` key — Blazor splats that as a
    // real DOM event handler on the wrapper (same mechanism Button uses to forward
    // the Slot's onmouseenter/onfocusin handlers).
    private IReadOnlyDictionary<string, object> TriggerAttributes
    {
        get
        {
            var d = new Dictionary<string, object>
            {
                // Disabled triggers leave the tab order entirely; enabled ones become
                // the focusable host now that the inner <button> is tabindex=-1.
                ["tabindex"] = Disabled ? "-1" : "0",
                ["onkeydown"] = EventCallback.Factory.Create<KeyboardEventArgs>(this, HandleTriggerKeyDown),
            };
            if (AdditionalAttributes is not null)
                foreach (var kv in AdditionalAttributes) d[kv.Key] = kv.Value; // author wins on collision
            return d;
        }
    }

    // When the button is disabled while its menu is open, the trigger becomes
    // pointer-events-none and DropdownMenuTrigger.Toggle early-returns on
    // Disabled, so the user can no longer click to dismiss — the menu would be
    // stranded open over a disabled control. Force-close on the disable edge.
    protected override void OnParametersSet()
    {
        if (Disabled && !_wasDisabled && _open)
        {
            _open = false;
        }

        _wasDisabled = Disabled;
    }

    // Keyboard entry point for the WAI-ARIA menu-button pattern (triage #114).
    // The trigger wrapper is now the focusable host (its inner <button> is
    // tabindex=-1), but a role=button div has no native key activation, so the
    // open logic lives here:
    //   • Enter / Space  -> toggle the menu (open when closed).
    //   • ArrowDown / ArrowUp -> open the menu; DropdownMenuContent then moves
    //     roving focus into the list on the next Arrow press.
    // Disabled triggers stay inert. preventDefault is intentionally NOT applied
    // via the @onkeydown:preventDefault directive — that would also swallow Tab
    // and trap focus inside the trigger; the menu-open is the observable effect.
    private void HandleTriggerKeyDown(Microsoft.AspNetCore.Components.Web.KeyboardEventArgs e)
    {
        if (Disabled) return;

        switch (e.Key)
        {
            case "Enter":
            case " ":
            case "Spacebar": // legacy IE/Edge key name for the spacebar
                _open = !_open;
                break;
            case "ArrowDown":
            case "ArrowUp":
                _open = true;
                break;
        }
    }
}
